+import React, { useEffect, useState } from 'react';
 import React from 'react';
+import classNames from 'classnames';
 import Window from './Window';
 import TorchLight from './TorchLight';
 import Character from './Character';

+// Cycle duration in milliseconds
+const CYCLE_DURATION = 5 * 60 * 1000;
+
+function getCycleProgress() {
+  return (Date.now() % CYCLE_DURATION) / CYCLE_DURATION;
+}
+
+function getTheme(progress) {
+  // progress 0 to 0.5 = day, 0.5 to 1 = night
+  if (progress < 0.5) return 'day';
+  return 'night';
+}
+
 export default function RoomView(props) {
-  return (
-    <div className="room-view">
-      <Window />
-      <TorchLight />
-      <Character />
-    </div>
-  );
+  const [cycleProgress, setCycleProgress] = useState(getCycleProgress());
+
+  useEffect(() => {
+    const interval = setInterval(() => {
+      setCycleProgress(getCycleProgress());
+    }, 1000);
+    return () => clearInterval(interval);
+  }, []);
+
+  const theme = getTheme(cycleProgress);
+
+  // Calculate color adjustment for characters (slight tint)
+  // Day: warm tint, Night: blue tint, interpolate smoothly
+  const tintAmount = theme === 'day'
+    ? 1 - cycleProgress * 2 // 1 to 0 over day half
+    : (cycleProgress - 0.5) * 2; // 0 to 1 over night half
+
+  return (
+    <div className={classNames('room-view', theme)}>
+      <Window theme={theme} cycleProgress={cycleProgress} />
+      <TorchLight theme={theme} />
+      <Character tintAmount={tintAmount} theme={theme} />
+    </div>
+  );
 }
