+import React from 'react';
+
+export default function Window({ theme, cycleProgress }) {
+  // Show stars only at night
+  const showStars = theme === 'night';
+
+  // Stars opacity pulses slightly with cycle progress for subtle twinkle
+  const starOpacity = 0.6 + 0.4 * Math.sin(cycleProgress * 2 * Math.PI * 10);
+
+  return (
+    <div className="window">
+      {showStars ? (
+        <div className="stars" style={{ opacity: starOpacity }}>
+          {/* Simple star dots */}
+          <span className="star" style={{ top: '10%', left: '20%' }}>★</span>
+          <span className="star" style={{ top: '30%', left: '70%' }}>★</span>
+          <span className="star" style={{ top: '60%', left: '40%' }}>★</span>
+          <span className="star" style={{ top: '80%', left: '80%' }}>★</span>
+        </div>
+      ) : (
+        <div className="daylight">Sunlight</div>
+      )}
+    </div>
+  );
 }
