+export default function TorchLight({ theme }) {
+  // Torch light intensity stronger at night
+  const intensity = theme === 'night' ? 1 : 0.4;
+  return (
+    <div
+      className="torch-light"
+      style={{
+        filter: `brightness(${intensity}) drop-shadow(0 0 8px orange)`,
+        transition: 'filter 1s ease',
+      }}
+    />
+  );
 }
