+import React from 'react';
+
+export default function Character({ tintAmount, theme }) {
+  // Apply color tint: day = warm (orange), night = blue
+  // tintAmount from 0 to 1 controls intensity
+  const dayTint = `rgba(255, 165, 0, ${1 - tintAmount})`; // orange fade out
+  const nightTint = `rgba(0, 0, 255, ${tintAmount})`; // blue fade in
+
+  const tintStyle = {
+    backgroundColor: 'transparent',
+    boxShadow: `inset 0 0 10px ${dayTint}, inset 0 0 10px ${nightTint}`,
+    transition: 'box-shadow 1s ease',
+  };
+
+  return <div className="character" style={tintStyle} />;
 }
